import{_ as e,c as a,o,ag as r}from"./chunks/framework.DD2hp6gW.js";const u=JSON.parse('{"title":"Textarea Field","description":"","frontmatter":{},"headers":[],"relativePath":"fields/textarea.md","filePath":"fields/textarea.md","lastUpdated":null}'),i={name:"fields/textarea.md"};function l(n,t,s,d,c,h){return o(),a("div",null,t[0]||(t[0]=[r('<h1 id="textarea-field" tabindex="-1">Textarea Field <a class="header-anchor" href="#textarea-field" aria-label="Permalink to &quot;Textarea Field&quot;">​</a></h1><p>The <strong>Textarea</strong> field provides a larger, multi-line text box for customers to enter longer messages or detailed instructions. Unlike the single-line Text Input, the Textarea expands vertically to accommodate paragraphs of text.</p><h2 id="common-use-cases" tabindex="-1">Common Use Cases <a class="header-anchor" href="#common-use-cases" aria-label="Permalink to &quot;Common Use Cases&quot;">​</a></h2><ul><li>Long gift notes or personal messages</li><li>Special delivery or handling instructions</li><li>Detailed customization requirements (e.g., cake decoration descriptions)</li><li>Custom product specifications or notes to the seller</li></ul><h2 id="field-settings" tabindex="-1">Field Settings <a class="header-anchor" href="#field-settings" aria-label="Permalink to &quot;Field Settings&quot;">​</a></h2><p>When you add a Textarea field and expand it in the builder, the following settings are available:</p><h3 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Label</strong></td><td style="text-align:left;">The title displayed above the textarea on the product page (e.g., &quot;Gift Message&quot;).</td></tr><tr><td style="text-align:left;"><strong>Description</strong></td><td style="text-align:left;">Optional help text shown below the field to guide the customer (e.g., &quot;Maximum 200 characters&quot;).</td></tr><tr><td style="text-align:left;"><strong>Required</strong></td><td style="text-align:left;">When checked, the customer must enter text before adding the product to the cart.</td></tr></tbody></table><h3 id="placeholder" tabindex="-1">Placeholder <a class="header-anchor" href="#placeholder" aria-label="Permalink to &quot;Placeholder&quot;">​</a></h3><p>You can set <strong>Placeholder</strong> text that appears as faded hint text inside the textarea (e.g., &quot;Type your full message here...&quot;). This text disappears as soon as the customer starts typing.</p><h3 id="pricing" tabindex="-1">Pricing <a class="header-anchor" href="#pricing" aria-label="Permalink to &quot;Pricing&quot;">​</a></h3><p>Since the Textarea is not an options-based field, pricing is configured at the <strong>field level</strong>:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Price Type</strong></td><td style="text-align:left;">Choose how the field affects the product price. Available types: <strong>No Price</strong>, <strong>Flat Fee</strong>, <strong>Percentage of Base</strong>, <strong>Per Character</strong>, or <strong>Formula</strong>.</td></tr><tr><td style="text-align:left;"><strong>Price Amount</strong></td><td style="text-align:left;">The numeric value to apply.</td></tr><tr><td style="text-align:left;"><strong>Formula</strong></td><td style="text-align:left;">(Only when Price Type is &quot;Formula&quot;) A math expression using placeholders like <code>[value]</code>, <code>[char_count]</code>, <code>[base_price]</code>, and <code>[quantity]</code>.</td></tr></tbody></table><h3 id="restrictions" tabindex="-1">Restrictions <a class="header-anchor" href="#restrictions" aria-label="Permalink to &quot;Restrictions&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Min Length</strong></td><td style="text-align:left;">The minimum number of characters the customer must enter.</td></tr><tr><td style="text-align:left;"><strong>Max Length</strong></td><td style="text-align:left;">The maximum number of characters allowed. Useful for limiting the length of engraving or embroidery text.</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Combine <strong>Per Character</strong> pricing with a <strong>Max Length</strong> restriction to let customers know exactly what their customization will cost. For example, &quot;Each character costs $0.25, maximum 150 characters.&quot;</p></div><h2 id="conditional-logic" tabindex="-1">Conditional Logic <a class="header-anchor" href="#conditional-logic" aria-label="Permalink to &quot;Conditional Logic&quot;">​</a></h2><p>You can show or hide this field based on the value of another field in the same group. For example, you might only show a &quot;Special Instructions&quot; textarea when the customer selects &quot;Custom Order&quot; from a dropdown.</p><p>For full details on setting up rules, see the <a href="./../conditional-logic.html">Conditional Logic</a> page.</p>',19)]))}const p=e(i,[["render",l]]);export{u as __pageData,p as default};
